"""
Scenario #1: SQL Injection

Opis:
    Ta datoteka simulira del spletne aplikacije za prikaz uporabniškega profila.
    Aplikacija prejme uporabnikov ID iz HTTP GET parametra in ga uporabi za
    sestavljanje SQL poizvedbe.

Kaj datoteka dela:
    - definira enostaven Logger
    - definira UserRepository za delo z uporabniki
    - vsebuje metodo get_user_by_id(), ki sestavi SQL query
    - vsebuje tudi nekaj varnih metod, da datoteka ni samo minimalen primer

Ranljivost:
    Uporabniški input iz request.GET["id"] se najprej shrani v spremenljivko user_id.
    Nato se user_id neposredno prilepi v SQL query z uporabo string concatenation.

Nevarna vrstica:
    query = "SELECT * FROM users WHERE id='" + user_id + "'"

Zakaj je nevarno:
    Napadalec lahko spremeni vrednost parametra id in s tem spremeni pomen SQL poizvedbe.

Pričakovan rezultat analizatorja:
    Scenario #1: SQL Injection
    Risk: HIGH
"""

class Logger:
    def info(self, message):
        print("[INFO]", message)

    def error(self, message):
        print("[ERROR]", message)


class UserFormatter:
    def format_user(self, user):
        return {
            "id": user.get("id"),
            "name": user.get("name"),
            "email": user.get("email")
        }

    def format_error(self, message):
        return {
            "status": "error",
            "message": message
        }


class UserRepository:
    def __init__(self, cursor, logger):
        self.cursor = cursor
        self.logger = logger

    def get_default_query(self):
        query = "SELECT * FROM users WHERE active=1"
        return query

    def list_active_users(self):
        query = self.get_default_query()
        self.logger.info("Listing active users")
        self.cursor.execute(query)

    def get_user_by_id(self, request):
        user_id = request.GET["id"]

        # VULNERABILITY: SQL Injection
        # User input is concatenated directly into the SQL query.
        query = "SELECT * FROM users WHERE id='" + user_id + "'"

        self.logger.info("Getting user by id")
        self.cursor.execute(query)

        return query

    def count_users(self):
        query = "SELECT COUNT(*) FROM users"
        self.cursor.execute(query)
        return query


class UserController:
    def __init__(self, repository, formatter):
        self.repository = repository
        self.formatter = formatter

    def show_user(self, request):
        try:
            query = self.repository.get_user_by_id(request)
            return {
                "status": "ok",
                "query": query
            }
        except Exception:
            return self.formatter.format_error("Could not load user")


def helper_clean_value(value):
    if value is None:
        return ""

    return str(value).strip()


def main():
    logger = Logger()
    formatter = UserFormatter()

    # cursor is assumed to be provided by the application
    cursor = None

    repository = UserRepository(cursor, logger)
    controller = UserController(repository, formatter)

    return controller

"""
Scenario #2: HQL / ORM Injection

Opis:
    Ta datoteka simulira del aplikacije za iskanje uporabniškega računa.
    Namesto klasične SQL poizvedbe uporablja ORM/HQL-style poizvedbo prek createQuery().

Kaj datoteka dela:
    - definira Logger
    - definira AccountRepository za delo z računi
    - vsebuje metodo get_account_from_request(), ki sestavi HQL/ORM query
    - query se nato posreduje v session.createQuery()

Ranljivost:
    Uporabniški input iz request.GET["id"] se shrani v customer_id.
    Nato se customer_id neposredno prilepi v HQL/ORM query.
    Ta query se nato izvede prek createQuery().

Nevarne vrstice:
    query = "FROM accounts WHERE custID='" + customer_id + "'"
    return self.session.createQuery(query)

Zakaj je nevarno:
    Če je uporabniški input neposredno vključen v ORM/HQL query,
    lahko napadalec spremeni logiko poizvedbe in pridobi nepooblaščen dostop do podatkov.

Pričakovan rezultat analizatorja:
    Scenario #2: HQL Injection
    Risk: HIGH
"""

class Logger:
    def info(self, message):
        print("[INFO]", message)


class AccountFormatter:
    def format_account(self, account):
        return {
            "id": account.get("id"),
            "owner": account.get("owner"),
            "balance": account.get("balance")
        }

    def empty_response(self):
        return {
            "status": "empty",
            "data": None
        }


class AccountRepository:
    def __init__(self, session, logger):
        self.session = session
        self.logger = logger

    def get_all_accounts_query(self):
        return "FROM accounts"

    def list_accounts(self):
        query = self.get_all_accounts_query()
        self.logger.info("Listing accounts")
        return self.session.createQuery(query)

    def get_account_from_request(self, request):
        customer_id = request.GET["id"]

        # VULNERABILITY: HQL / ORM Injection
        # User input is concatenated directly into the ORM query.
        query = "FROM accounts WHERE custID='" + customer_id + "'"

        self.logger.info("Loading account from request")
        return self.session.createQuery(query)

    def get_demo_account(self):
        query = "FROM accounts WHERE custID='demo'"
        return self.session.createQuery(query)


class AccountController:
    def __init__(self, repository, formatter):
        self.repository = repository
        self.formatter = formatter

    def show_account(self, request):
        account = self.repository.get_account_from_request(request)

        if account is None:
            return self.formatter.empty_response()

        return {
            "status": "ok",
            "data": account
        }


def normalize_customer_id(value):
    if value is None:
        return "0"

    return str(value).strip()


def main():
    logger = Logger()
    formatter = AccountFormatter()

    # session is assumed to be provided by ORM framework
    session = None

    repository = AccountRepository(session, logger)
    controller = AccountController(repository, formatter)

    return controller

"""
Scenario #3: Command Injection

Opis:
    Ta datoteka simulira del aplikacije za preverjanje DNS/domene.
    Aplikacija prejme ime domene iz HTTP GET parametra in sestavi sistemski ukaz nslookup.

Kaj datoteka dela:
    - definira Logger
    - definira DomainValidator
    - definira NetworkService za izvajanje omrežnih operacij
    - vsebuje metodo lookup_domain(), ki sestavi ukaz in ga izvede z os.system()

Ranljivost:
    Uporabniški input iz request.GET["domain"] se shrani v domain.
    Nato se domain neposredno prilepi v sistemski ukaz.
    Ukaz se izvede prek os.system(cmd).

Nevarne vrstice:
    cmd = "nslookup " + domain
    self.os.system(cmd)

Zakaj je nevarno:
    Napadalec lahko v parameter domain vstavi dodatne ukaze in tako povzroči izvajanje
    neželenih sistemskih ukazov na strežniku.

Pričakovan rezultat analizatorja:
    Scenario #3: Command Injection
    Risk: HIGH
"""
class Logger:
    def info(self, message):
        print("[INFO]", message)

    def error(self, message):
        print("[ERROR]", message)


class DomainValidator:
    def is_empty(self, value):
        return value is None or value == ""

    def normalize(self, value):
        if value is None:
            return ""

        return str(value).strip()


class NetworkService:
    def __init__(self, logger, os_module):
        self.logger = logger
        self.os = os_module

    def ping_static_host(self):
        cmd = "ping example.com"
        self.logger.info("Running static ping")
        self.os.system(cmd)

    def lookup_domain(self, request):
        domain = request.GET["domain"]

        # VULNERABILITY: Command Injection
        # User input is concatenated directly into the OS command.
        cmd = "nslookup " + domain

        self.logger.info("Running domain lookup")
        self.os.system(cmd)

    def show_help(self):
        return "Use domain parameter to perform lookup"


class NetworkController:
    def __init__(self, service, validator):
        self.service = service
        self.validator = validator

    def lookup(self, request):
        domain = request.GET["domain"]

        if self.validator.is_empty(domain):
            return {
                "status": "error",
                "message": "Missing domain"
            }

        self.service.lookup_domain(request)

        return {
            "status": "ok",
            "domain": domain
        }


def build_response(status, message):
    return {
        "status": status,
        "message": message
    }


def main():
    logger = Logger()
    validator = DomainValidator()

    # os module is assumed to be injected by application
    os_module = None

    service = NetworkService(logger, os_module)
    controller = NetworkController(service, validator)

    return controller

def get_user(request, users):
    username = request.args["username"]
    filter_query = {"username": username}
    return users.find_one(filter_query)

def mongodb_operator_direct_example(request, users):
    username = request.args["username"]
    return users.find_one({"username": {"$ne": username}})
